VGetExtrema Example

VB Example:

Dim xmin As Single, xmax As Single

Dim ymin As Single, ymax As Single

Dim seq As String, blob As String

seq = "testSeq"

blob = "blob01"

m_spel.VRun(seq)

m_spel.VGet(seq, blob, "found", found)

If found <> 0 Then

  m_spel.VGetExtrema(seq, blob, xmin, xmax, ymin, ymax)

End If

C# Example:

float xMin, xMax, yMin, yMax;

bool found;

string seq, blob;

seq = "testSeq";

blob = "blob01";

m_spel.VRun(seq);

m_spel.VGet(seq, blob, "found", found);

if(found == true)

  m_spel.VGetExtrema(seq, blob,out xMin,out xMax,out yMin, out yMax);

